from __future__ import annotations

import base64
import hashlib
from pathlib import Path
import zlib

PAYLOAD = ""

patch = zlib.decompress(base64.b64decode(PAYLOAD))
assert hashlib.sha256(patch).hexdigest() == "83fe718930b39563f3649d7b02f0c2ea611a8622c822dac36047733c33e1389c"
Path("/tmp/astro-kld.patch").write_bytes(patch)
